#include "base/task/task_executor.h"
#include "core/components_ng/pattern/web/web_pattern.h"
#include "core/pipeline_ng/pipeline_context.h"

namespace OHOS::Ace::NG {

class WebDelegate {
public:
    WebDelegate(const RefPtr<TaskExecutor>& executor) : executor_(executor) {}

    void OnPageLoaded(const std::string& url) {
        executor_->PostTask([this, url]() {
            auto pattern = pattern_.Upgrade();
            if (!pattern) {
                return;
            }
            pattern->OnPageLoaded(url);
            UpdateNavigationHistory(url);
        }, TaskExecutor::TaskType::UI);
    }

    void OnResourceLoadComplete(int32_t httpStatus) {
        executor_->PostDelayedTask([this, httpStatus]() {
            auto host = GetHost();
            if (!host) {
                return;
            }
            host->MarkDirtyNode(PROPERTY_UPDATE_MEASURE);
            LOGI("Resource load complete: %{public}d", httpStatus);
        }, 500, TaskExecutor::TaskType::UI);
    }

    void OnSslErrorReceived(const std::string& url, int32_t errorCode) {
        executor_->PostTask([this, url, errorCode]() {
            auto pattern = pattern_.Upgrade();
            if (pattern) {
                pattern->HandleSslError(url, errorCode);
            }
            lastErrorUrl_ = url;
            lastErrorCode_ = errorCode;
        }, TaskExecutor::TaskType::UI);
    }

    void ScheduleCleanup() {
        executor_->PostDelayedTask([this]() {
            pendingResources_.clear();
            cachedResponses_.clear();
        }, 3000, TaskExecutor::TaskType::BACKGROUND);
    }

private:
    WeakPtr<WebPattern> pattern_;
    RefPtr<TaskExecutor> executor_;
    std::string lastErrorUrl_;
    int32_t lastErrorCode_ = 0;
    std::vector<std::string> pendingResources_;
    std::map<std::string, std::string> cachedResponses_;
    RefPtr<FrameNode> GetHost() { return nullptr; }
};

