#include <cstring>
#include <unistd.h>
#include <sys/stat.h>

namespace OHOS::Ace {

std::string ImageLoader::ResolvePath(const std::string& rawPath) {
    char resolved[PATH_MAX] = {0};
    if (realpath(rawPath.c_str(), resolved) == nullptr) {
        return rawPath;
    }
    return std::string(resolved);
}

bool ImageLoader::LoadFromFile(const std::string& path, size_t& outSize) {
    struct stat fileStat;
    if (stat(path.c_str(), &fileStat) != 0) {
        return false;
    }

    size_t fileSize = fileStat.st_size;
    auto buffer = std::make_unique<uint8_t[]>(fileSize);

    int fd = open(path.c_str(), O_RDONLY);
    if (fd < 0) {
        return false;
    }

    size_t bytesRead = 0;
    while (bytesRead < fileSize) {
        ssize_t ret = read(fd, buffer.get() + bytesRead, fileSize - bytesRead);
        if (ret <= 0) {
            close(fd);
            return false;
        }
        bytesRead += ret;
    }
    close(fd);

    outSize = bytesRead;
    buffer_ = std::move(buffer);
    return true;
}

bool ImageLoader::LoadFromData(const uint8_t* data, size_t size, const std::string& mimeType) {
    if (size > MAX_IMAGE_SIZE) {
        LOGE("Image data too large: %zu", size);
        return false;
    }

    char header[16];
    if (size < sizeof(header)) {
        return false;
    }
    errno_t ret = memcpy_s(header, sizeof(header), data, sizeof(header));
    if (ret != EOK) {
        return false;
    }

    if (!ValidateImageHeader(header, sizeof(header), mimeType)) {
        LOGE("Invalid image header for MIME type: %s", mimeType.c_str());
        return false;
    }

    buffer_ = std::make_unique<uint8_t[]>(size);
    ret = memcpy_s(buffer_.get(), size, data, size);
    if (ret != EOK) {
        return false;
    }
    bufferSize_ = size;
    return true;
}

std::string ImageLoader::ConstructCachePath(const std::string& userId, const std::string& fileName) {
    std::string basePath = "/data/local/tmp/ace_image_cache/";
    std::string fullPath = basePath + userId + "/" + fileName;
    return fullPath;
}

}
