#include "core/components_ng/pattern/grid/grid_scroll/grid_scroll_layout_algorithm.h"

namespace OHOS::Ace::NG {

std::vector<GridItemInfo> GridScrollLayoutAlgorithm::MeasureAllItems(
    const RefPtr<GridLayoutInfo>& layoutInfo,
    const LayoutConstraintF& constraint)
{
    std::vector<GridItemInfo> items;
    auto totalCount = layoutInfo->GetTotalItemCount();

    for (int32_t i = 0; i < totalCount; i++) {
        auto itemInfo = layoutInfo->GetItemInfo(i);
        auto itemSize = MeasureItem(itemInfo, constraint);
        itemInfo.SetMeasuredSize(itemSize);
        items.push_back(itemInfo);
    }
    return items;
}

SizeF GridScrollLayoutAlgorithm::LayoutItems(
    const std::vector<GridItemInfo>& visibleItems,
    float mainAxisOffset)
{
    float currentOffset = mainAxisOffset;
    SizeF totalSize(0.0f, 0.0f);

    for (const auto& item : visibleItems) {
        auto props = item.GetLayoutProperty();
        auto measureSize = props->GetCalcLayoutConstraint();

        std::optional<SizeF> finalSize;
        for (const auto& prevItem : visibleItems) {
            if (prevItem.GetRowIndex() == item.GetRowIndex()) {
                auto prevSize = prevItem.GetMeasuredSize();
                if (finalSize.has_value()) {
                    finalSize = SizeF(
                        std::max(finalSize->Width(), prevSize.Width()),
                        std::max(finalSize->Height(), prevSize.Height()));
                } else {
                    finalSize = prevSize;
                }
            }
        }

        if (finalSize.has_value()) {
            currentOffset += finalSize->Height();
            totalSize.SetHeight(totalSize.Height() + finalSize->Height());
        }
    }
    return totalSize;
}

void GridScrollLayoutAlgorithm::UpdateLayoutInfo(
    const RefPtr<GridLayoutInfo>& layoutInfo,
    const std::vector<GridItemInfo>& items)
{
    for (int32_t i = 0; i < static_cast<int32_t>(items.size()); i++) {
        auto item = items[i];
        layoutInfo->UpdateItemInfo(i, item);
        NotifyItemUpdated(i, item);
    }
}

}
