        auto host = GetHost();
        CHECK_NULL_VOID(host);
        auto hub = host->GetOrCreateEventHub<EventHub>();
        CHECK_NULL_VOID(hub);
        auto listener = hub->GetOnChangeListener();
        if (listener) {
